import React from "react";

export default function ProfileScreen({ user = { name: "", email: "", joinedDate: "" }, darkMode }) {
  const formatDate = (dateStr) => {
    if (!dateStr) return "-";
    const d = new Date(dateStr);
    return d.toLocaleDateString(undefined, { year: "numeric", month: "long", day: "numeric" });
  };
const handleLogout = () => {
  localStorage.removeItem("authToken");
  window.location.reload();
};

  return (
    <div className={`px-6 pb-24 min-h-screen ${darkMode ? "bg-gray-900 text-gray-100" : "bg-gray-50 text-gray-900"}`}>
      <h1 className="text-2xl font-bold mb-6">Profile</h1>

      <div className={`bg-white p-6 rounded-2xl border ${darkMode ? "border-gray-700 bg-gray-800" : "border-gray-100"} shadow-sm space-y-4`}>
        <p><span className="font-semibold">Name:</span> {user.name}</p>
        <p><span className="font-semibold">Email:</span> {user.email}</p>
        <p>
          <span className="font-semibold">Joined:</span> {formatDate(user.joinedDate)}
        </p>
      </div>

      <button
        className={`mt-6 w-full py-3 rounded-xl transition-colors ${darkMode ? "bg-red-700 hover:bg-red-600 text-white" : "bg-red-600 hover:bg-red-700 text-white"}`}
        onClick={handleLogout}
      >
        Logout
      </button>
    </div>
  );
}
